var exportCSV = false;
if (options.export) {
    if (options.export.toLowerCase() === 'csv') {
        exportCSV = true;
    }
}

var AWSConfig;

// OPTION 1: Configure AWS credentials through hard-coded key and secret
// AWSConfig = {
//     accessKeyId: '',
//     secretAccessKey: '',
//     sessionToken: '',
//     region: 'us-east-1'
// };

AWSConfig = require(__dirname + '/credentials.json');

// OPTION 3: ENV configuration with AWS_ env vars
if(process.env.AWS_ACCESS_KEY_ID && process.env.AWS_SECRET_ACCESS_KEY){
    AWSConfig = {
        accessKeyId: process.env.AWS_ACCESS_KEY_ID,
        secretAccessKey:  process.env.AWS_SECRET_ACCESS_KEY,
        sessionToken: process.env.AWS_SESSION_TOKEN,
        region: process.env.AWS_DEFAULT_REGION || 'us-east-1'
    };
}

if (!AWSConfig || !AWSConfig.accessKeyId) {
    return console.log('ERROR: Invalid AWSConfig');
}

var skipRegions = [];   // Add any regions you wish to skip here. Ex: 'us-east-2'

// Custom settings - place plugin-specific settings here
var settings = {};

// STEP 1 - Obtain API calls to make
console.log('INFO: Determining API calls to make...');

var apiCalls = [];

for (p in plugins) {
    for (a in plugins[p].apis) {
        if (apiCalls.indexOf(plugins[p].apis[a]) === -1) {
            apiCalls.push(plugins[p].apis[a]);
        }
    }
}

console.log('INFO: API calls determined.');
console.log('INFO: Collecting AWS metadata. This may take several minutes...');

// STEP 2 - Collect API Metadata from AWS
collector(AWSConfig, {api_calls: apiCalls, skip_regions: skipRegions}, function(err, collection){
    if (err || !collection) return console.log('ERROR: Unable to obtain API metadata');

    console.log('INFO: Metadata collection complete. Analyzing...');
    console.log('INFO: Analysis complete. Scan report to follow...\n');

    if (exportCSV) {
        var writer = csvWriter({headers: ["category", "title", "resource", "region", "statusWord", "message"]});
        writer.pipe(fs.createWriteStream('results.csv'));
    }

    async.forEachOfLimit(plugins, 10, function(plugin, key, callback){
        plugin.run(collection, settings, function(err, results){
            for (r in results) {
                var statusWord;
                if (results[r].status === 0) {
                    statusWord = 'OK';
                } else if (results[r].status === 1) {
                    statusWord = 'WARN';
                } else if (results[r].status === 2) {
                    statusWord = 'FAIL';
                } else {
                    statusWord = 'UNKNOWN';
                }

                console.log(plugin.category + '\t' + plugin.title + '\t' +
                            (results[r].resource || 'N/A') + '\t' +
                            (results[r].region || 'Global') + '\t\t' +
                            statusWord + '\t' + results[r].message);


		//if the user asks us to export to csv lets do that
		if (exportCSV) {
		    writer.write([plugin.category, plugin.title, (results[r].resource || 'N/A'), (results[r].region || 'Global'), statusWord, results[r].message])
		}
            }

            callback(err);
        });
    }, function(err){
        if (err) return console.log(err);
    });

    if (exportCSV) {
        writer.end();
        console.log('INFO: Results available at results.csv.');
    }
});
```

I think that i have found an issue in how ExaBGP formats the messages with the announced prefixes.

The problem is the list of the prefixes is surrounded by curly braces which imply an object and if the list contains VPNV4 prefixes a duplicate name may arise.

This is a simplified example of what i have found in a production environment:
```
"announce": { 
  "ipv4 mpls-vpn": { 
    "192.0.2.1": { 
      "198.51.100.0/29": { "label": [ 11903 ], "route-distinguisher": "65412:1" }, 
      "198.51.100.0/29": { "label": [ 48298 ], "route-distinguisher": "64512:2" }
    }
  }
}
```

If you parse the above with json or ujson (Python here) they will dump the object as follows:
```
"announce": { 
  "ipv4 mpls-vpn": { 
    "192.0.2.1": { 
      "198.51.100.0/29": { "label": [ 48298 ], "route-distinguisher": "64512:2" }
    }
  }
}
``` 

That is beacuse the JSON specifications state that an object is a dictionary-like collection of name/value pairs.

I'd suggest to format the list as follows:
```
"announce": { 
  "ipv4 mpls-vpn": { 
    "192.0.2.1": { 
      "64512:1:198.51.100.0/29": { "label": [ 11903 ], "route-distinguisher": "65412:1" }, 
      "64512:2:198.51.100.0/29": { "label": [ 48298 ], "route-distinguisher": "64512:2" }
    }
  }
}
```

I got the original codec from url "FAHR%E2%80%A2WERK", it's "FAHR•WERK" in utf-8.
But when I use chardet.detect, the result is {'confidence': 0.73, 'encoding': 'windows-1252'}
and the confidence of the utf-8 is only 0.505.
And I think there's sth wrong with utf8prober. So I look into utf8prober.py, and find code below:

``` python
elif coding_state == MachineState.start:
    if self.coding_sm.get_current_charlen() >= 2:
        self._num_mb_chars += 1
```

It seems only multibyte character can be judged as an utf-8 character.
So codec like "FAHR%E2%80%A2WERK" get a very low confidence.

In this case , I think we should judge the the single byte character also as an utf-8 character.
So I change the code into:

``` python
elif coding_state == MachineState.start:
    if self.coding_sm.get_current_charlen() >= 1:
        self._num_mb_chars += 1
```

and the result is {'confidence': 0.99, 'encoding': 'utf-8'}

